  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_category_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=5682 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
