INSERT INTO `cms_pages` VALUES (1,'index','index','','','{\"page\":\"index\",\"heroTitle\":\"专业资金解决方案\\n助力企业稳健发展\",\"heroSubtitle\":\"提供上市公司短拆、企业摆账、银行存款、应收账款融资等全方位资金服务，以专业实力和丰富经验，为您的企业发展保驾护航。\",\"stat1Number\":\"10+\",\"stat1Label\":\"年行业经验\",\"stat2Number\":\"500+\",\"stat2Label\":\"服务企业\",\"stat3Number\":\"100亿+\",\"stat3Label\":\"亿资金规模\",\"stat4Number\":\"99%\",\"stat4Label\":\"%客户满意度\",\"servicesTitle\":\"核心业务领域\",\"servicesSubtitle\":\"涵盖上市公司、企业摆账、银行存款、应收账款融资等全方位资金服务\",\"service1Title\":\"上市公司类\",\"service1Content\":\"<ul><li>短拆、股票解质押过桥<\\/li><li class=\\\"\\\">募集账户归还过桥、产业基金备案过桥<\\/li><li>股票质押、定增、协议转让、代持<\\/li><li>财务报表优化、降负债<\\/li><\\/ul>\",\"service2Title\":\"企业\\/个人摆账\",\"service2Content\":\"<ul><li class=\\\"\\\">长短期定存摆账、云信票据实摆<\\/li><li class=\\\"\\\">过账实趴、抵押类资金过桥<\\/li><li class=\\\"\\\">实缴验资、资金证明、银行保函<\\/li><li class=\\\"\\\">贸易增量、显账亮资<\\/li><\\/ul>\",\"service3Title\":\"银行存款类\",\"service3Content\":\"<ul><li class=\\\"\\\">时点冲量、日均业务<\\/li><li class=\\\"\\\">月末冲量<\\/li><li>一年期定期存款<\\/li><li>三年期定期存款<\\/li><\\/ul>\",\"service4Title\":\"应收账款融资\",\"service4Content\":\"<ul><li>置换云信票据<\\/li><li class=\\\"\\\">可拆分流转支付<\\/li><li class=\\\"\\\">融资贴现、准入宽松<\\/li><li>不看征信、包容执行诉讼主体<\\/li><\\/ul>\",\"advantagesTitle\":\"服务优势\",\"advantagesSubtitle\":\"专业、高效、安全\",\"faqTitle\":\"常见问题\",\"faqSubtitle\":\"解答您关于资金业务的常见疑问\"}','2026-05-06 05:47:35','2026-05-03 01:32:55'),(2,'services','services','业务范围','涵盖上市公司、企业摆账、银行存款、应收账款融资等全方位资金服务','{\"page\":\"services\",\"title\":\"业务范围\",\"subtitle\":\"涵盖上市公司、企业摆账、银行存款、应收账款融资等全方位资金服务\",\"sections\":[{\"id\":\"services-list\",\"content\":\"\\n                    <div class=\\\"services-v2-grid\\\">\\n                        <!-- 业务模块 1: 上市公司类 -->\\n                        <article class=\\\"service-v2-card\\\" data-module-id=\\\"1\\\">\\n                            <div class=\\\"service-v2-header\\\">\\n                                <div class=\\\"service-v2-icon-large\\\">\\n                                    <i class=\\\"fas fa-chart-line\\\" aria-hidden=\\\"true\\\"><\\/i>\\n                                <\\/div>\\n                            <\\/div>\\n                            <div class=\\\"service-v2-body\\\">\\n                                <h3 class=\\\"service-v2-title\\\">上市公司类<\\/h3>\\n                                <p class=\\\"service-v2-desc\\\">为上市公司提供专业资金解决方案，助力企业资本运作<\\/p>\\n                                <ul class=\\\"service-v2-list\\\">\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 短拆、股票解质押过桥<\\/li>\\n                                    <li class=\\\"\\\"><i class=\\\"fas fa-check\\\"><\\/i> 募集账户归还过桥、产业基金备案过桥<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 股票质押、定增、协议转让、代持<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 财务报表优化、降负债<\\/li>\\n                                <\\/ul>\\n                                <div class=\\\"service-v2-footer\\\">\\n                                    <button class=\\\"btn btn-primary btn-sm\\\">了解详情<\\/button>\\n                                <\\/div>\\n                            <\\/div>\\n                        <\\/article>\\n\\n                        <!-- 业务模块 2: 企业\\/个人摆账 -->\\n                        <article class=\\\"service-v2-card\\\" data-module-id=\\\"2\\\">\\n                            <div class=\\\"service-v2-header\\\">\\n                                <div class=\\\"service-v2-icon-large\\\">\\n                                    <i class=\\\"fas fa-hand-holding-usd\\\" aria-hidden=\\\"true\\\"><\\/i>\\n                                <\\/div>\\n                            <\\/div>\\n                            <div class=\\\"service-v2-body\\\">\\n                                <h3 class=\\\"service-v2-title\\\">企业\\/个人摆账<\\/h3>\\n                                <p class=\\\"service-v2-desc\\\">灵活多样的摆账方案，满足各类资金展示需求<\\/p>\\n                                <ul class=\\\"service-v2-list\\\">\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 长短期定存摆账、云信票据实摆<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 过账实趴、抵押类资金过桥<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 实缴验资、资金证明、银行保函<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 贸易增量、显账亮资<\\/li>\\n                                <\\/ul>\\n                                <div class=\\\"service-v2-footer\\\">\\n                                    <button class=\\\"btn btn-primary btn-sm\\\">了解详情<\\/button>\\n                                <\\/div>\\n                            <\\/div>\\n                        <\\/article>\\n\\n                        <!-- 业务模块 3: 银行存款类 -->\\n                        <article class=\\\"service-v2-card\\\" data-module-id=\\\"3\\\">\\n                            <div class=\\\"service-v2-header\\\">\\n                                <div class=\\\"service-v2-icon-large\\\">\\n                                    <i class=\\\"fas fa-university\\\" aria-hidden=\\\"true\\\"><\\/i>\\n                                <\\/div>\\n                            <\\/div>\\n                            <div class=\\\"service-v2-body\\\">\\n                                <h3 class=\\\"service-v2-title\\\">银行存款类<\\/h3>\\n                                <p class=\\\"service-v2-desc\\\">专业银行存款冲量服务，优化企业财务报表<\\/p>\\n                                <ul class=\\\"service-v2-list\\\">\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 时点冲量、日均业务<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 月末冲量<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 一年期定期存款<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 三年期定期存款<\\/li>\\n                                <\\/ul>\\n                                <div class=\\\"service-v2-footer\\\">\\n                                    <button class=\\\"btn btn-primary btn-sm\\\">了解详情<\\/button>\\n                                <\\/div>\\n                            <\\/div>\\n                        <\\/article>\\n\\n                        <!-- 业务模块 4: 应收账款融资 -->\\n                        <article class=\\\"service-v2-card\\\" data-module-id=\\\"4\\\">\\n                            <div class=\\\"service-v2-header\\\">\\n                                <div class=\\\"service-v2-icon-large\\\">\\n                                    <i class=\\\"fas fa-file-invoice-dollar\\\" aria-hidden=\\\"true\\\"><\\/i>\\n                                <\\/div>\\n                            <\\/div>\\n                            <div class=\\\"service-v2-body\\\">\\n                                <h3 class=\\\"service-v2-title\\\">应收账款融资<\\/h3>\\n                                <p class=\\\"service-v2-desc\\\">盘活应收账款，加速资金周转，助力企业发展<\\/p>\\n                                <ul class=\\\"service-v2-list\\\">\\n                                    <li class=\\\"\\\"><i class=\\\"fas fa-check\\\"><\\/i> 置换云信票据<\\/li>\\n                                    <li class=\\\"\\\"><i class=\\\"fas fa-check\\\"><\\/i> 可拆分流转支付<\\/li>\\n                                    <li class=\\\"\\\"><i class=\\\"fas fa-check\\\"><\\/i> 融资贴现、准入宽松<\\/li>\\n                                    <li><i class=\\\"fas fa-check\\\"><\\/i> 不看征信、包容执行诉讼主体<\\/li>\\n                                <\\/ul>\\n                                <div class=\\\"service-v2-footer\\\">\\n                                    <button class=\\\"btn btn-primary btn-sm\\\">了解详情<\\/button>\\n                                <\\/div>\\n                            <\\/div>\\n                        <\\/article>\\n                    <\\/div>\\n                \"},{\"id\":\"services-details\",\"content\":\"\\n                    <div class=\\\"service-details-custom\\\">\\n                        <div class=\\\"detail-custom-card\\\">\\n                            <div class=\\\"detail-custom-icon\\\">\\n                                <i class=\\\"fas fa-star\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"detail-custom-title\\\">核心优势<\\/h4>\\n                            <ul class=\\\"detail-custom-list\\\">\\n                                <li>资金实力雄厚，单笔可提供数亿至数十亿资金支持<\\/li>\\n                                <li>操作灵活，可根据客户需求定制个性化方案<\\/li>\\n                                <li>审批快速，资料齐全后最快当日放款<\\/li>\\n                                <li>合规安全，严格遵循金融监管要求<\\/li>\\n                            <\\/ul>\\n                        <\\/div>\\n                        <div class=\\\"detail-custom-card\\\">\\n                            <div class=\\\"detail-custom-icon\\\">\\n                                <i class=\\\"fas fa-calculator\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"detail-custom-title\\\">收费说明<\\/h4>\\n                            <ul class=\\\"detail-custom-list\\\">\\n                                <li>按实际使用天数计费，透明无隐藏费用<\\/li>\\n                                <li class=\\\"\\\">根据资金规模、期限、风险等级综合定价<\\/li>\\n                                <li>长期合作客户享受优惠费率<\\/li>\\n                                <li>具体费用以双方签署协议为准<\\/li>\\n                            <\\/ul>\\n                        <\\/div>\\n                        <div class=\\\"detail-custom-card\\\">\\n                            <div class=\\\"detail-custom-icon\\\">\\n                                <i class=\\\"fas fa-shield-alt\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"detail-custom-title\\\">风险提示<\\/h4>\\n                            <ul class=\\\"detail-custom-list\\\">\\n                                <li>资金业务存在市场风险，请根据自身情况谨慎决策<\\/li>\\n                                <li>请确保提供真实、完整的资料信息<\\/li>\\n                                <li>严格遵守合同约定，按时归还资金<\\/li>\\n                                <li>投资有风险，入市需谨慎<\\/li>\\n                            <\\/ul>\\n                        <\\/div>\\n                    <\\/div>\\n                \"},{\"id\":\"services-process\",\"content\":\"\\n                    <div class=\\\"section-header\\\" style=\\\"margin-top: 80px;\\\">\\n                        <div class=\\\"section-label\\\">PROCESS<\\/div>\\n                        <h2 class=\\\"section-title\\\">服务流程<\\/h2>\\n                        <p class=\\\"section-subtitle\\\">专业高效的服务流程，确保业务顺利开展<\\/p>\\n                    <\\/div>\\n\\n                    <div class=\\\"process-custom-grid\\\">\\n                        <div class=\\\"process-custom-item\\\">\\n                            <div class=\\\"process-custom-number\\\">01<\\/div>\\n                            <div class=\\\"process-custom-icon\\\">\\n                                <i class=\\\"fas fa-comments\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"process-custom-title\\\">需求沟通<\\/h4>\\n                            <p class=\\\"process-custom-desc\\\">了解客户资金需求，评估业务可行性<\\/p>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-arrow\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"><\\/i>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-item\\\">\\n                            <div class=\\\"process-custom-number\\\">02<\\/div>\\n                            <div class=\\\"process-custom-icon\\\">\\n                                <i class=\\\"fas fa-file-alt\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"process-custom-title\\\">资料审核<\\/h4>\\n                            <p class=\\\"process-custom-desc\\\">风控审核，确立操作性<\\/p>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-arrow\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"><\\/i>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-item\\\">\\n                            <div class=\\\"process-custom-number\\\">03<\\/div>\\n                            <div class=\\\"process-custom-icon\\\">\\n                                <i class=\\\"fas fa-check-circle\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"process-custom-title\\\">账户新开<\\/h4>\\n                            <p class=\\\"process-custom-desc\\\">账户激活后，签署协议控材料<\\/p>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-arrow\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"><\\/i>\\n                        <\\/div>\\n                        <div class=\\\"process-custom-item\\\">\\n                            <div class=\\\"process-custom-number\\\">04<\\/div>\\n                            <div class=\\\"process-custom-icon\\\">\\n                                <i class=\\\"fas fa-handshake\\\"><\\/i>\\n                            <\\/div>\\n                            <h4 class=\\\"process-custom-title\\\">进款和出款<\\/h4>\\n                            <p class=\\\"process-custom-desc\\\">出款后归还材料，协议撕毁结束<\\/p>\\n                        <\\/div>\\n                    <\\/div>\\n                \"}]}','2026-05-04 10:46:05','2026-05-03 01:32:55'),(3,'cases','cases','成功案例','多年来，我们已成功服务数百家企业，累计管理资金规模超百亿。每一个案例都是我们专业能力的见证。','{\"page\":\"cases\",\"title\":\"成功案例\",\"subtitle\":\"多年来，我们已成功服务数百家企业，累计管理资金规模超百亿。每一个案例都是我们专业能力的见证。\"}','2026-05-04 07:44:29','2026-05-03 01:32:55'),(4,'contact','联系我们','联系我们',NULL,NULL,'2026-05-03 01:32:55','2026-05-03 01:32:55'),(1173,'faq','faq','常见问题','解答您关于资金业务的常见疑问','{\"page\":\"faq\",\"title\":\"常见问题\",\"subtitle\":\"解答您关于资金业务的常见疑问\",\"sections\":[{\"id\":\"faq-search\",\"content\":\"\\n                    <div class=\\\"faq-search-box\\\">\\n                        <i class=\\\"fas fa-search\\\"><\\/i>\\n                        <input type=\\\"text\\\" class=\\\"faq-search-input\\\" placeholder=\\\"搜索问题关键词...\\\">\\n                        <button class=\\\"faq-search-btn\\\">搜索<\\/button>\\n                    <\\/div>\\n                \"},{\"id\":\"faq-categories\",\"content\":\"\\n                    <div class=\\\"faq-categories\\\" id=\\\"faqCategoryButtons\\\">\\n                    <div class=\\\"faq-category-item active\\\" data-category=\\\"all\\\">\\n                        <i class=\\\"fas fa-th-large\\\"><\\/i>\\n                        <span>全部问题<\\/span>\\n                    <\\/div>\\n                \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"baizhang\\\">\\n                            <i class=\\\"fas fa-university\\\"><\\/i>\\n                            <span>摆账业务<\\/span>\\n                        <\\/div>\\n                    \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"general\\\">\\n                            <i class=\\\"fas fa-info-circle\\\"><\\/i>\\n                            <span>一般问题<\\/span>\\n                        <\\/div>\\n                    \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"receivable\\\">\\n                            <i class=\\\"fas fa-file-invoice-dollar\\\"><\\/i>\\n                            <span>云信融资出表<\\/span>\\n                        <\\/div>\\n                    \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"bridge\\\">\\n                            <i class=\\\"fas fa-exchange-alt\\\"><\\/i>\\n                            <span class=\\\"\\\">过桥资金<\\/span>\\n                        <\\/div>\\n                    \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"liangzi\\\">\\n                            <i class=\\\"fas fa-lightbulb\\\"><\\/i>\\n                            <span>亮资业务<\\/span>\\n                        <\\/div>\\n                    \\n                        <div class=\\\"faq-category-item\\\" data-category=\\\"deposit\\\">\\n                            <i class=\\\"fas fa-landmark\\\"><\\/i>\\n                            <span>银行存款<\\/span>\\n                        <\\/div>\\n                    <\\/div>\\n                \"},{\"id\":\"faq-list\",\"content\":\"\\n                    <div class=\\\"faq-custom-container\\\">\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"baizhang\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-university\\\"><\\/i>\\n                                        摆账业务\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">摆账和亮资有什么区别？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                <p>摆账和亮资虽然都涉及资金展示，但在操作方式和应用场景上有所不同：<\\/p>\\n<table class=\\\"faq-custom-table\\\">\\n<tbody>\\n<tr>\\n<th>对比项<\\/th>\\n<th>摆账<\\/th>\\n<th>亮资<\\/th>\\n<\\/tr>\\n<tr>\\n<td>主要用途<\\/td>\\n<td>财务报表优化、审计、年检<\\/td>\\n<td>向第三方展示资金实力<\\/td>\\n<\\/tr>\\n<tr>\\n<td>展示对象<\\/td>\\n<td>审计机构、监管部门<\\/td>\\n<td>合作方、招标方等<\\/td>\\n<\\/tr>\\n<tr>\\n<td>时间要求<\\/td>\\n<td>通常需要保持一定时期<\\/td>\\n<td>时点或短期展示<\\/td>\\n<\\/tr>\\n<tr>\\n<td>操作方式<\\/td>\\n<td>资金存入账户并保持<\\/td>\\n<td>资金展示后可能转出<\\/td>\\n<\\/tr>\\n<\\/tbody>\\n<\\/table>\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>摆账业务安全吗？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                根据客户需求和用途，摆账业务主要分为以下类型：\\n\\n时点摆账：在特定时间点（如月末、季末、年末）保持资金在账\\n日均摆账：在一段时间内保持日均存款余额达标\\n定期摆账：以定期存款形式摆账，期限灵活\\n实缴验资：用于企业注册资本实缴验资\\n资金证明：用于开具资金证明、银行保函等\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div>\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"general\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-info-circle\\\"><\\/i>\\n                                        一般问题\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list cms-editable-selected\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>什么是过桥资金？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                过桥资金是一种短期融资方式，主要用于企业在银行贷款到期续贷期间的临时资金周转。我们可以提供1-6个月的短期资金支持，帮助企业顺利完成银行续贷流程。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>云信票据融资有什么优势？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                云信票据融资相比传统融资方式具有以下优势：\\n\\n准入宽松：对融资企业资质要求相对宽松\\n不看征信：不查询企业征信记录\\n包容执行：可接受有执行诉讼记录的企业\\n灵活流转：云信票据可拆分、可流转、可支付\\n融资便捷：审批流程简单，放款速度快\\n成本可控：融资成本透明，综合成本较低\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>服务流程是怎样的？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                我们的服务流程如下：\\n\\n需求沟通：了解客户资金需求，评估业务可行性\\n资料审核：风控审核，确立操作性\\n账户新开：账户激活后，签署协议控材料\\n进款和出款：出款后归还材料，协议撕毁结束\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\"><\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                测试\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div>\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"receivable\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-file-invoice-dollar\\\"><\\/i>\\n                                        云信融资出表\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">什么样的应收账款可以融资？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                一般来说，以下类型的应收账款更容易获得融资：\\n\\n与核心企业（国企、央企、上市公司等）产生的应收账款\\n账期在6个月以内的应收账款\\n贸易背景真实、合同发票齐全的应收账款\\n付款方信用良好的应收账款\\n我们接受云信、商票等多种形式的应收账款融资申请，具体可融资额度需要根据应收账款的具体情况评估。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">应收账款融资额度如何确定？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                融资额度主要根据以下因素综合评估：\\n\\n应收账款金额：融资金额通常不超过应收账款面额\\n付款方信用等级：国企、央企、上市公司等信用等级高，融资比例高\\n账期长短：账期越短，融资比例越高\\n历史交易记录：长期合作客户可享受更高融资比例\\n一般可融资金额为应收账款面额的70%-95%，具体比例根据实际情况确定。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div>\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"bridge\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-exchange-alt\\\"><\\/i>\\n                                        过桥资金\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>过桥资金适用于哪些场景？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                过桥资金主要适用于以下场景：\\n银行贷款续贷：原贷款到期，新贷款尚未放款期间的临时周转\\n股票解质押：上市公司股东解除股票质押时的临时资金需求\\n募集账户归还：上市公司募集资金归还时的临时周转\\n企业并购：并购交易中的临时资金安排\\n项目保证金：招投标、履约保证金等临时资金需求\\n资金周转：企业短期资金周转困难时的临时支持\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">申请过桥资金需要什么条件？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                申请过桥资金通常需要提供以下资料：\\n\\n企业营业执照、组织机构代码证\\n法定代表人身份证明\\n财务报表（近三个月）\\n资金用途说明\\n还款来源证明（如银行批贷函、应收账款证明等）\\n抵押担保资料（如有）\\n具体资料清单根据业务类型有所不同，我们的客户经理会根据您的具体情况提供详细的资料清单。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">过桥资金多久可以放款？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                资料齐全且审核通过后，最快可在当日放款。一般情况下，从申请到放款需要1-3个工作日。  放款速度主要取决于：  资料准备的完整程度 审核流程的复杂程度 资金调度的安排 对于紧急需求，我们提供加急服务，可在最短时间内完成放款。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div>\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"liangzi\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-lightbulb\\\"><\\/i>\\n                                        亮资业务\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>什么是亮资业务？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                亮资业务是指企业在参与招投标、项目洽谈、商务合作等场景时，需要向对方展示资金实力的服务。我们提供大额资金在客户账户中展示，证明企业具备相应的资金履约能力。\\n\\n亮资业务通常分为时点亮资和时期亮资两种形式：\\n\\n时点亮资：在特定时间点展示资金，通常用于投标现场、商务谈判等场景\\n时期亮资：在一段时间内保持资金在账，通常用于项目履约保证金、合同履约等\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>亮资业务需要多长时间？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                根据客户需求，亮资业务可分为时点亮资和时期亮资：\\n\\n时点亮资：通常在1-3个工作日内完成，资金在约定时间点展示\\n时期亮资：根据约定期限，从几天到数月不等，资金在约定期限内保持在账\\n具体时长需要根据客户的具体需求和业务场景来确定。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span>亮资业务收费如何计算？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                亮资业务收费主要根据以下因素综合确定：\\n\\n资金规模：展示的资金金额大小\\n亮资时长：展示资金的时间长度\\n操作复杂程度：是否需要跨行、异地等操作\\n时效要求：是否需要加急处理\\n具体费用需要根据实际情况评估，欢迎来电咨询获取详细报价。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div>\\n                                <div class=\\\"faq-custom-category\\\" data-category=\\\"deposit\\\">\\n                                    <h3 class=\\\"faq-custom-category-title\\\">\\n                                        <i class=\\\"fas fa-landmark\\\"><\\/i>\\n                                        银行存款\\n                                    <\\/h3>\\n                                    <div class=\\\"faq-custom-list\\\">\\n                            \\n                                        <details class=\\\"faq-custom-item\\\">\\n                                            <summary class=\\\"faq-custom-question\\\">\\n                                                <span class=\\\"\\\">银行存款业务有什么优势？<\\/span>\\n                                                <i class=\\\"fas fa-chevron-down\\\"><\\/i>\\n                                            <\\/summary>\\n                                            <div class=\\\"faq-custom-answer\\\">\\n                                                我们与多家银行建立了长期合作关系，可以为客户争取更优惠的存款利率，同时提供专业的资金管理建议。\\n                                            <\\/div>\\n                                        <\\/details>\\n                                    <\\/div><\\/div><\\/div>\\n                \"},{\"id\":\"faq-more\",\"content\":\"\\n                    <div class=\\\"faq-more-box\\\">\\n                        <div class=\\\"faq-more-icon\\\">\\n                            <i class=\\\"fas fa-headset\\\"><\\/i>\\n                        <\\/div>\\n                        <div class=\\\"faq-more-content\\\">\\n                            <h3>还有其他问题？<\\/h3>\\n                            <p>欢迎随时联系我们的专业顾问，我们将竭诚为您解答<\\/p>\\n                        <\\/div>\\n                        <div class=\\\"contact-button-wrapper\\\">\\n                            <button class=\\\"btn btn-primary\\\" id=\\\"faqConsultBtn\\\">\\n                                <i class=\\\"fas fa-phone-alt\\\"><\\/i>\\n                                联系我们\\n                            <\\/button>\\n                            <span id=\\\"faqPhoneDisplay\\\" style=\\\"display:none;font-size:18px;font-weight:700;color:#1e3a8a;letter-spacing:2px;white-space:nowrap;\\\">13552883008<\\/span>\\n                        <\\/div>\\n                    <\\/div>\\n                \"}]}','2026-05-04 09:21:08','2026-05-04 09:21:08'),(3134,'news','news','行业资讯','了解最新行业动态与业务资讯','{\"page\":\"news\",\"title\":\"行业资讯\",\"subtitle\":\"了解最新行业动态与业务资讯\",\"sections\":[{\"id\":\"news-categories\",\"content\":\"\\n                    <div class=\\\"news-categories\\\" id=\\\"newsCategories\\\"><a href=\\\"#\\\" class=\\\"news-category active\\\" data-cat-id=\\\"0\\\">全部资讯<\\/a><a href=\\\"#\\\" class=\\\"news-category\\\" data-cat-id=\\\"5\\\">企业摆账<\\/a><a href=\\\"#\\\" class=\\\"news-category\\\" data-cat-id=\\\"1\\\">过桥短拆<\\/a><a href=\\\"#\\\" class=\\\"news-category\\\" data-cat-id=\\\"4\\\">实缴验资<\\/a><a href=\\\"#\\\" class=\\\"news-category\\\" data-cat-id=\\\"2\\\">显账亮资<\\/a><a href=\\\"#\\\" class=\\\"news-category\\\" data-cat-id=\\\"3\\\">金融知识<\\/a><\\/div>\\n                \"},{\"id\":\"news-featured\",\"content\":\"\\n                    <div class=\\\"news-featured-grid\\\">\\n                        <!-- 精选资讯卡片已删除 -->\\n              