INSERT INTO `faq` VALUES (1,'liangzi','什么是亮资服务？','亮资服务是指企业在投标、合作洽谈等场景中，需要向对方展示自身资金实力时，由专业机构提供的资金证明服务。',NULL,NULL,NULL,1,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-06 06:36:09'),(2,'liangzi','亮资需要多长时间？','<p>一般情况下，亮资服务可在1-3个工作日内完成，具体时间根据金额大小和银行要求而定。</p>',NULL,NULL,NULL,2,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(3,'guoqiao','过桥资金的利率是多少？','<p>过桥资金利率根据金额、期限、风险等因素综合确定，一般在月息1%-3%之间，具体费率需根据实际情况评估。</p>',NULL,NULL,NULL,1,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(4,'guoqiao','过桥资金最长可以使用多久？','<p>过桥资金通常为短期资金周转，使用期限一般在1-6个月，最长不超过1年。</p>',NULL,NULL,NULL,2,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(5,'baizhang','摆账业务的资金安全吗？','<p>我们提供的摆账服务资金来源合法合规，全程由银行监管，确保资金安全。同时会签订正规合同，保障双方权益。</p>',NULL,NULL,NULL,1,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(6,'baizhang','摆账需要提供什么资料？','<p>一般需要提供：营业执照、法人身份证、公司章程、银行开户许可证等基础资料，具体要求根据摆账金额和银行要求而定。</p>',NULL,NULL,NULL,2,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(7,'receivable','应收账款融资的额度是多少？','<p>应收账款融资额度一般为应收账款金额的50%-80%，具体比例根据应收账款质量、账期、买方信用等因素确定。</p>',NULL,NULL,NULL,1,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(8,'deposit','银行存款业务有什么优势？','<p>我们与多家银行建立了长期合作关系，可以为客户争取更优惠的存款利率，同时提供专业的资金管理建议。</p>',NULL,NULL,NULL,1,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(10,'general','如何联系你们？','<p>您可以通过以下方式联系我们：<br>电话：13552883008<br>邮箱：wanglizhongguo@126.com<br>或直接在网站上点击\"立即咨询\"按钮。</p>',NULL,NULL,NULL,2,1,'',NULL,NULL,'2026-05-04 08:46:54','2026-05-04 08:46:54'),(18,'general','这什么？','测试a',NULL,NULL,NULL,0,1,'',NULL,NULL,'2026-05-10 08:17:42','2026-05-10 08:17:42'),(19,'general','测试二','<p>测试二</p>',NULL,NULL,NULL,0,1,'','','','2026-05-10 13:52:14','2026-05-10 13:52:14');
/*!40000 ALTER TABLE `faq` ENABLE KEYS */;
UNLOCK TABLES;

