INSERT INTO `faq_categories` VALUES (552,'general','一般问题',NULL,NULL,NULL,0,'企业个人摆账验资常见问题解答','企业摆账问题，注册资金实缴疑问，个人摆账常见咨询','汇总企业摆账、个人摆账、注册资金实缴验资常见一般问题，讲解办理资料、流程、费用、周期及异地操作注意事项。','2026-05-10 13:49:44'),(553,'baizhang','企业摆账',NULL,NULL,NULL,1,'企业摆账服务_大额企业实摆账 / 显账资金办理','企业摆账，企业显账，实摆账，企业资金摆账服务','专业提供企业摆账、实摆账、企业显账服务，大额资金支持，合规操作，快速办结企业资金业务','2026-05-10 13:49:44'),(554,'guoqiao','实缴验资',NULL,NULL,NULL,2,'注册资金实缴验资服务_企业验资 / 实缴资金办理','实缴验资，注册资金实缴，企业验资，验资报告办理','提供企业注册资金实缴验资、大额资金实缴服务，合规出具验资报告，助力企业工商注册 / 项目审批。','2026-05-10 13:49:44'),(555,'liangzi','显账亮资',NULL,NULL,NULL,3,'企业显账亮资服务_工程 / 项目资金证明办理','显账亮资，企业亮资，资金证明，工程显账服务','专业办理企业显账、大额亮资、项目 / 工程资金证明业务，资金实力雄厚，满足投标、审批等场景资金需求。','2026-05-10 13:49:44'),(556,'deposit','资金证明',NULL,NULL,NULL,4,'企业 / 个人资金证明办理_大额资金证明服务','资金证明，企业资金证明，个人资金证明，银行资金证明','专业办理企业 / 个人大额资金证明业务，包含银行资金证明、项目资金证明，合规操作，快速出证。','2026-05-10 13:49:44'),(557,'receivable','云信融资出表',NULL,NULL,NULL,5,'云信融资出表服务_应收账款融资 / 企业出表办理','云信融资出表，应收账款融资，企业出表，资金出表服务','专业办理云信融资出表、应收账款融资业务，解决企业合规出表需求，高效落地企业资金周转方案。','2026-05-10 13:49:44');
