INSERT INTO `pages` VALUES (1,'index','首页','<h1>专业资金解决方案</h1><p>提供上市公司短拆、企业摆账、银行存款、应收账款融资等全方位资金服务</p>','宏都资本-专业资金业务服务商',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(2,'services','业务范围','<h1>业务范围</h1><p>涵盖上市公司、企业摆账、银行存款、应收账款融资等全方位资金服务</p>','宏都资本业务范围',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(3,'cases','成功案例','<h1>成功案例</h1><p>多年来，我们已成功服务数百家企业，累计管理资金规模超百亿</p>','宏都资本成功案例',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(4,'advantages','服务优势','<h1>服务优势</h1><p>专业团队、丰富经验、高效服务</p>','宏都资本服务优势',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(5,'news','行业资讯','<h1>行业资讯</h1><p>最新行业动态和政策解读</p>','宏都资本行业资讯',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(6,'faq','常见问题','<h1>常见问题</h1><p>解答您的疑问</p>','宏都资本常见问题',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31'),(7,'contact','联系我们','<h1>联系我们</h1><p>电话：3552883008</p>','宏都资本联系方式',NULL,1,0,'2026-04-29 13:35:31','2026-04-29 13:35:31');
