INSERT INTO `seo_settings` VALUES (1,'global','要资金网 - 过桥短拆 | 摆账亮资 | 资金证明 | 过账 | 银行存款','上市公司短拆，股票解质押过桥，企业摆账，个人亮资，资金证明，实缴验资，银行冲量，定期存款，应收账款买断，云信票据置换，优化财务报表，降负债','专业资金服务平台，主营上市公司短拆、股票解质押过桥、募集账户归还过桥、企业个人摆账亮资、实缴验资、资金证明、银行时点日均冲量、定期存款、应收账款买断及云信票据置换，优化财务报表、增资产降负债，矿产收购、工程保证金、三角债清理均可操作，诚邀渠道代理合作。','2026-05-05 10:15:17'),(4,'faq_new.html','资金业务常见问题 | 摆账验资 - 亮资显账操作指南','企业摆账流程，过桥短拆注意事项，工程亮资咨询，实缴验资问题，银行冲量常见疑问','解答企业摆账、过桥短拆、工程亮资、实缴验资、银行冲量等资金业务操作流程与注意事项，一站式消除合作疑问。','2026-05-05 10:15:17'),(6,'index.html','Yao 资金网 | 企业摆账 - 过桥短拆一站式资金业务服务','企业摆账，过桥短拆，银行冲量，实缴验资，工程亮资','提供企业摆账、过桥短拆、银行冲量、实缴验资、工程亮资等一站式资金业务服务，高效合规，专业对接。','2026-05-05 10:15:17'),(7,'services.html','资金业务服务范围 | 企业摆账 - 过桥短拆解决方案','企业摆账业务，过桥短拆，银行存款冲量，实缴验资，工程亮资','覆盖企业摆账、过桥短拆、银行冲量、实缴验资、工程亮资等多种资金业务场景，按需定制方案。','2026-05-05 10:15:17'),(8,'cases.html','资金业务成功案例 | 企业摆账 - 过桥短拆真实案例','企业摆账案例，过桥短拆案例，银行冲量案例，实缴验资，工程亮资案例','展示多行业资金业务成功案例，包含企业摆账、过桥短拆、银行冲量、实缴验资、工程亮资等场景参考。','2026-05-05 10:15:17'),(9,'case-detail.html','工程亮资实缴验资资金服务案例 | Yao 资金网','工程亮资案例，实缴验资案例，过桥短拆流程，企业摆账操作','分享工程亮资、企业实缴验资、过桥短拆完整流程与合规解决方案，适合项目投标与企业验资使用。','2026-05-05 10:15:17'),(10,'advantages.html','资金业务服务优势 | 高效合规资金服务','专业资金服务，过桥短拆，工程亮资，实缴验资，企业摆账优势','多年行业经验，高效合规一站式资金服务，解决企业资金周转、过桥短拆、工程亮资、实缴验资各类资金需求。','2026-05-05 10:15:17'),(11,'news.html','资金行业资讯 | 企业摆账 - 过桥短拆行业动态','资金行业新闻，企业融资资讯，银行冲量政策，工程亮资新规，实缴验资政策','提供资金行业最新政策、市场动态解读，包含过桥短拆、工程亮资、实缴验资、企业摆账行业新规资讯。','2026-05-05 10:15:17'),(12,'news-detail.html','2026 工程亮资与实缴验资业务新规解读 | Yao 资金网','2026 工程亮资与实缴验资业务新规解读 | Yao 资金网','解读 2026 年工程亮资、企业实缴验资、过桥短拆行业新规，为企业项目投标、验资出凭提供合规参考。','2026-05-05 10:15:17'),(13,'faq.html','资金业务常见问题解答 | 企业摆账 - 过桥短拆疑问','企业摆账问题，过桥短拆疑问，银行冲量，工程亮资咨询，实缴验资常见问题','解答企业摆账、过桥短拆、银行冲量、工程亮资、实缴验资等资金业务常见疑问，打消合作顾虑。','2026-05-05 10:15:17'),(14,'contact.html','联系我们 | 资金业务咨询对接','资金业务咨询，企业摆账对接，过桥短拆合作，工程亮资合作，实缴验资咨询','欢迎咨询企业摆账、过桥短拆、银行冲量、工程亮资、实缴验资业务，快速定制专属资金方案。','2026-05-05 10:15:17'),(15,'privacy.html','隐私政策 | 用户信息保护说明','网站隐私政策，用户信息保护，资金业务信息安全','说明网站收集、使用及保护用户信息规则，保障过桥短拆、工程亮资、实缴验资业务咨询用户隐私安全','2026-05-05 10:15:17'),(16,'compliance.html','合规声明 | Yao 资金网业务合规说明','资金业务合规声明，企业摆账合规，过桥短拆合规，工程亮资合规，实缴验资合规条款','本网站过桥短拆、工程亮资、实缴验资、企业摆账等资金业务均在合规框架内开展，明确业务免责与合规说明。','2026-05-05 10:15:17'),(17,'sitemap.html','网站地图 | Yao 资金网全站导航','网站地图，资金业务导航，过桥短拆，工程亮资，实缴验资，企业摆账页面索引','Yao 资金网全站导航，快速查找企业摆账、过桥短拆、工程亮资、实缴验资所有业务页面。','2026-05-05 10:15:17'),(33,'readme.html','关于 Yao 资金网 | 企业摆账 - 过桥短拆一站式服务','资金业务服务介绍，企业摆账平台说明，过桥短拆服务说明','Yao 资金网专注提供企业摆账、过桥短拆、银行冲量、工程亮资、实缴验资等一站式资金业务服务。','2026-05-05 10:15:17'),(48,'test-api.html','测试','','','2026-05-05 10:15:07');
